Every counter returns n because var is shared across iterations. Fix so makeCounters(3) yields counters returning 0, 1, 2. counters.mjs:
export function makeCounters(n) {
  const fns = [];
  for (var i = 0; i < n; i++) {
    fns.push(() => i);
  }
  return fns;
}

